function cta(label,target){var ic=' <svg viewBox="0 0 24 24" fill="none"><path d="M5 12h14M13 6l6 6-6 6" stroke="'+CV()+'" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>';if(target&&target.indexOf('__key__:')===0){return '<button class="cta" data-hos-key="'+String(target.slice(8)).replace(/"/g,'&quot;')+'">'+label+ic+'</button>';}if(target&&target.indexOf('__ask__:')===0){return '<button class="cta" data-hos-ask="'+String(target.slice(8)).replace(/"/g,'&quot;')+'">'+label+ic+'</button>';}if(target==='__browse__'){return '<button class="cta" data-hos-browse="1">'+label+ic+'</button>';}if(target==='__book__'){return '<button class="cta" data-hos-book="1">'+label+ic+'</button>';}var href=(LINKS[target]!==undefined)?LINKS[target]:target;if(href&&href.indexOf('calendly.com')>-1){return '<button class="cta" data-hos-cal="'+href+'">'+label+ic+'</button>';}if(href&&href.indexOf('go.mindbodyonline.com')>-1){return '<button class="cta" data-hos-mbo="'+href+'" data-mbo-title="'+label+'">'+label+ic+'</button>';}return '<a class="cta" href="'+href+'" target="_blank" rel="noopener">'+label+ic+'</a>';}
function CV(){try{return getComputedStyle(document.documentElement).getPropertyValue('--nv')||'#112133';}catch(e){return '#112133';}}
