function openTeach(){kbLvl=0;if(!teachpop)return;if(teachIn)teachIn.classList.remove('tv');if(teachBack)teachBack.style.display='none';if(teachShare)teachShare.style.display='none';if(teachTitle)teachTitle.innerHTML=TEACHTITLE;teachBody.innerHTML='';var l=document.createElement('div');l.className='chippop-list';KNOW.forEach(function(sec,si){l.appendChild(kbChip(sec.name,function(){kbSection(si);}));});teachBody.appendChild(l);audShow(false);teachpop.classList.add('open');}
function kbSection(si){kbLvl=1;kbSi=si;audShow(false);var sec=KNOW[si];if(!sec){openTeach();return;}if(teachIn)teachIn.classList.remove('tv');if(teachBack)teachBack.style.display='inline-block';if(teachShare)teachShare.style.display='none';if(teachTitle)teachTitle.innerHTML=sec.name;teachBody.innerHTML='';var tp=sec.topics||[];if(!tp.length){var m=document.createElement('div');m.className='small';m.style.margin='0';m.innerHTML=(MSGS.libraryEmpty||'More coming soon.');teachBody.appendChild(m);return;}var l=document.createElement('div');l.className='chippop-list';tp.forEach(function(t,ti){l.appendChild(kbChip(t.name,function(){kbTopic(si,ti);}));});teachBody.appendChild(l);}
function kbTopic(si,ti){kbLvl=2;kbSi=si;kbTi=ti;var t=KNOW[si].topics[ti];if(!t){kbSection(si);return;}if(teachIn)teachIn.classList.add('tv');if(teachBack)teachBack.style.display='inline-block';if(teachShare)teachShare.style.display='none';if(teachTitle)teachTitle.innerHTML=t.name;teachBody.innerHTML='';var sum=document.createElement('div');sum.className='teach-sum';sum.innerHTML=kbTxt(t.overview||'');teachBody.appendChild(sum);var wrap=document.createElement('div');wrap.className='teach-secs';var l=document.createElement('div');l.className='chippop-list';(t.subtopics||[]).forEach(function(u,ui){l.appendChild(kbChip(u.title,function(){kbPage(si,ti,ui);}));});wrap.appendChild(l);teachBody.appendChild(wrap);if(AUD&&AUD.on){audStop();audWrap(sum);audShow(true);}else{audShow(false);}}
function kbPage(si,ti,ui){kbLvl=3;kbSi=si;kbTi=ti;kbUi=ui;kbDeep=false;var sec=KNOW[si],t=sec.topics[ti],u=t.subtopics[ui];if(!u){kbTopic(si,ti);return;}if(teachIn)teachIn.classList.add('tv');if(teachBack)teachBack.style.display='inline-block';if(teachShare)teachShare.style.display='inline-block';kbCurTitle=u.title;if(teachTitle)teachTitle.innerHTML=u.title;teachBody.innerHTML='';var pv=document.createElement('div');pv.className='teach-pass';var ans=document.createElement('div');ans.innerHTML=kbTxt(u.answer||'');pv.appendChild(ans);if(u.deep&&u.deep.trim()){var tog=document.createElement('button');tog.className='teach-toggle';var deep=document.createElement('div');deep.className='teach-deep';deep.style.display='none';deep.innerHTML=kbTxt(u.deep);tog.innerHTML=(sec.expandLabel||'Go deeper')+' \u25BE';tog.onclick=function(){kbDeep=!kbDeep;deep.style.display=kbDeep?'block':'none';tog.innerHTML=(kbDeep?(sec.collapseLabel||'show less')+' \u25B4':(sec.expandLabel||'Go deeper')+' \u25BE');};pv.appendChild(tog);pv.appendChild(deep);}teachBody.appendChild(pv);var bar=document.createElement('div');bar.className='teach-sugbar';var sg=null;if(!u.noSuggest){if(u.suggest&&u.suggest.text){sg=u.suggest;}else if(!t.noSuggest&&t.suggest&&t.suggest.text){sg=t.suggest;}}if(sg){bar.innerHTML='<div class="sugg" style="margin-top:0;">'+sg.text+'</div><div class="cta-row" style="margin-top:8px;">'+cta(sg.label,sg.target)+'</div>';}teachBody.appendChild(bar);if(AUD&&AUD.on){audStop();audWrap(pv);audShow(true);audCollect();}else{audShow(false);}}
function kbShare(si,ti,ui,title){var url=location.href.split('#')[0]+'#kb='+si+'.'+ti+'.'+ui;if(navigator.share){navigator.share({title:title,url:url}).catch(function(){});}else if(navigator.clipboard){navigator.clipboard.writeText(url);kbToast('Link copied');}else{prompt('Copy this link',url);}}
function kbToast(m){if(!teachpop)return;var box=teachpop.querySelector('.chippop-in');if(!box)return;var t=document.createElement('div');t.textContent=m;t.style.cssText='position:absolute;left:50%;bottom:14px;transform:translateX(-50%);background:'+CV()+';color:#fff;padding:8px 16px;border-radius:999px;font-size:12px;z-index:70;';box.appendChild(t);setTimeout(function(){if(t.parentNode)t.parentNode.removeChild(t);},1600);}
if(teachBack){teachBack.onclick=function(){if(kbLvl===3){kbTopic(kbSi,kbTi);}else if(kbLvl===2){kbSection(kbSi);}else{openTeach();}};}
if(teachShare){teachShare.onclick=function(){kbShare(kbSi,kbTi,kbUi,kbCurTitle);};}
