var audEl=document.getElementById('hos-aud'),audPlayBtn=document.getElementById('hos-aud-play'),audRestartBtn=document.getElementById('hos-aud-restart'),audVoicesEl=document.getElementById('hos-aud-voices');
var audPlaying=false,audTimer=null,audWords=[],audPos=0,audVoice=0,audHeld=false;try{audVoice=parseInt(localStorage.getItem('hos_aud_voice')||'0',10)||0;}catch(e){}
var ICO_PLAY='&#9654;',ICO_PAUSE='&#9208;';
function audClearHi(){audWords.forEach(function(w){w.classList.remove('hl');});}
function audStop(){audPlaying=false;if(audTimer){clearInterval(audTimer);audTimer=null;}if(audPlayBtn)audPlayBtn.innerHTML=ICO_PLAY;audClearHi();if(teachBody)teachBody.classList.remove('kb-reading');audPos=0;}
function audPause(){audPlaying=false;if(audTimer){clearInterval(audTimer);audTimer=null;}if(audPlayBtn)audPlayBtn.innerHTML=ICO_PLAY;if(teachBody)teachBody.classList.remove('kb-reading');}
function audShow(v){if(!audEl)return;var vis=!!(v&&AUD&&AUD.on);audEl.classList.toggle('on',vis);if(!vis)audStop();}
function audRenderVoices(){if(!audVoicesEl)return;audVoicesEl.innerHTML='';var sel=document.createElement('select');sel.className='aud-sel';((AUD&&AUD.voices)||[]).forEach(function(v,i){var o=document.createElement('option');o.value=i;o.textContent=v.name;if(i===audVoice)o.selected=true;sel.appendChild(o);});sel.onchange=function(){audVoice=parseInt(sel.value,10)||0;try{localStorage.setItem('hos_aud_voice',String(audVoice));}catch(e){}};audVoicesEl.appendChild(sel);}
function audWrap(el){var kids=[].slice.call(el.childNodes);kids.forEach(function(n){if(n.nodeType===3){var parts=n.nodeValue.split(' '),frag=document.createDocumentFragment();parts.forEach(function(pt,pi){if(pi>0)frag.appendChild(document.createTextNode(' '));if(pt==='')return;var sp=document.createElement('span');sp.className='w';sp.textContent=pt;frag.appendChild(sp);});el.replaceChild(frag,n);}else if(n.nodeType===1&&n.className!=='teach-toggle'&&(''+n.className).indexOf('aud-')<0){audWrap(n);}});}
function audCollect(){audWords=[].slice.call(teachBody.querySelectorAll('.w'));}
function audHi(){audClearHi();var nn=(AUD&&AUD.highlightWords)||3;var start=audPos,end=audPos+nn;if(AUD&&AUD.highlightMode==='chunk'){start=Math.floor(audPos/nn)*nn;end=start+nn;}for(var i=start;i<end&&i<audWords.length;i++){if(audWords[i])audWords[i].classList.add('hl');}if(audWords[audPos]&&audWords[audPos].scrollIntoView)audWords[audPos].scrollIntoView({block:'nearest'});}
function audExpandDeep(){var tog=teachBody.querySelector('.teach-toggle'),deep=teachBody.querySelector('.teach-deep');if(deep&&deep.style.display==='none'){kbDeep=true;deep.style.display='block';var sec=KNOW[kbSi];if(tog)tog.innerHTML=((sec&&sec.collapseLabel)||'show less')+' &#9652;';}}
function audPlay(){if(kbLvl===3)audExpandDeep();audCollect();if(!audWords.length)return;audPlaying=true;if(teachBody)teachBody.classList.add('kb-reading');if(audPlayBtn)audPlayBtn.innerHTML=ICO_PAUSE;audHi();if(audTimer)clearInterval(audTimer);audTimer=setInterval(function(){audPos++;if(audPos>=audWords.length){audStop();return;}audHi();},340);}
function audToggle(){if(audPlaying)audPause();else audPlay();}
function audRestart(){audPos=0;audClearHi();if(audPlaying){audHi();}}
if(audPlayBtn){audPlayBtn.onclick=function(){if(audHeld){audHeld=false;return;}audToggle();};var _ht=null;audPlayBtn.addEventListener('pointerdown',function(){_ht=setTimeout(function(){audHeld=true;audRestart();},600);});var _hc=function(){if(_ht){clearTimeout(_ht);_ht=null;}};audPlayBtn.addEventListener('pointerup',_hc);audPlayBtn.addEventListener('pointerleave',_hc);}
if(audRestartBtn){audRestartBtn.onclick=audRestart;}
audRenderVoices();
