function renderChips(list){closeChipPop();curChips=list;chips.innerHTML='';list.forEach(function(it){var b=document.createElement('button');b.className='chip'+emphOf(it[0]);b.innerHTML=it[0];b.onclick=function(){handleUser(it[1],it[0]);};chips.appendChild(b);});chips.scrollTop=0;requestAnimationFrame(chipScrollHint);}
chips.addEventListener('scroll',chipScrollHint);window.addEventListener('resize',chipScrollHint);
var WIKI_EDITS={"off":{"Red Light Therapy — Panels vs masks, and EMF":true},"ed":{"Circadian Rhythm and Light":{"x":"Your circadian rhythm is the body's 24-hour clock, set mainly by light; getting light timing right supports sleep, mood, focus and long-term <strong>health</strong>."}}};
var KDOCS=[];(window.HOS_KNOWLEDGE||[]).forEach(function(d){if(WIKI_EDITS.off[d.t])return;var e=WIKI_EDITS.ed[d.t];KDOCS.push(e?{t:((e.t!=null&&e.t!=='')?e.t:d.t),s:d.s||'',x:(e.x!=null?e.x:d.x)}:d);});
var KSTOP={};'a an the and or of to in on for with is are was be by as at it its this that your you our we they them from can how what when where who why do does have has so my me im get also just really very'.split(' ').forEach(function(w){KSTOP[w]=1;});
function ktok(s){return (String(s).replace(/<[^>]+>/g,' ').toLowerCase().match(/[a-z0-9]+/g)||[]).filter(function(w){return w.length>1&&!KSTOP[w];});}
var KN=KDOCS.length,KDF={},KTOT=0,KDT=[];for(var ki=0;ki<KN;ki++){var tk=ktok((KDOCS[ki].t||'')+' '+(KDOCS[ki].t||'')+' '+(KDOCS[ki].x||''));KTOT+=tk.length;var tf={},seen={};for(var kj=0;kj<tk.length;kj++){tf[tk[kj]]=(tf[tk[kj]]||0)+1;if(!seen[tk[kj]]){seen[tk[kj]]=1;KDF[tk[kj]]=(KDF[tk[kj]]||0)+1;}}KDT.push({tf:tf,len:tk.length});}
var KAVG=KN?KTOT/KN:1;function kidf(t){var n=KDF[t]||0;return Math.log(1+(KN-n+0.5)/(n+0.5));}
function kSearch(q){if(!KN)return null;var qt=ktok(q);if(!qt.length)return null;qt=qt.map(function(t){if(KDF[t])return t;var s1=t.replace(/s$/,'');if(t.length>3&&KDF[s1])return s1;if(KDF[t+'s'])return t+'s';return t;});var qv=0;for(var qz=0;qz<qt.length;qz++){if(KDF[qt[qz]])qv++;}if(!qv)return null;var thr=(qv<2)?0.05:(KN<8?0.15:1.2);var best=-1,bi=-1;for(var i=0;i<KN;i++){var tf=KDT[i].tf,len=KDT[i].len,s=0;for(var j=0;j<qt.length;j++){var f=tf[qt[j]]||0;if(f)s+=kidf(qt[j])*(f*2.5)/(f+1.5*(0.25+0.75*len/KAVG));}if(s>best){best=s;bi=i;}}if(bi>=0&&qv===1&&qt.length>1){var mt=null;for(var mz=0;mz<qt.length;mz++){if(KDF[qt[mz]]){mt=qt[mz];break;}}var sig=(KDF[mt]>=2)||((KDOCS[bi].t||'').toLowerCase().indexOf(mt)>-1)||((KDT[bi].tf[mt]||0)>=2);if(!sig)return null;}if(bi>=0&&best>=thr){return {doc:KDOCS[bi],score:best};}return null;}
function kAnswer(res){var d=res.doc,txt=d.x||'';if(txt.length>800){txt=txt.slice(0,800).replace(/\s+\S*$/,'')+'\u2026';}return txt.replace(/\n/g,'<br>')+'<div class="src">'+MSGS.cite+' <em>'+d.t+'</em></div>';}
function answerFor(text){if(text.indexOf('__browse__')===0){return browseAnswer(text);}if(text.indexOf('__key__:')===0){var kr=keyAnswer(text.slice(8));return kr||{html:MSGS.fallback,cta:null,chips:STARTERS};}var t=' '+text.toLowerCase().replace(/[^\w\s$]/g,' ')+' ';var fw=text.toLowerCase().trim().split(/\s+/)[0];
if(/^\s*(explore|browse|topics|explore topics|browse topics|wiki|the wiki|knowledge base|library)\s*$/i.test(text)){return browseAnswer('__browse__');}
if(GREET.indexOf(text.toLowerCase().trim())>-1||(GREET.indexOf(fw)>-1&&text.trim().split(/\s+/).length<=2)){return {html:MSGS.greeting,cta:null,chips:(KB[0]&&KB[0].chips)};}
for(var g=0;g<THANKS.length;g++){if(t.indexOf(' '+THANKS[g])>-1&&text.trim().split(/\s+/).length<=4){return {html:MSGS.thanks,cta:null};}}
for(var lz=0;lz<LEADKW.length;lz++){if(t.indexOf(' '+LEADKW[lz])>-1){return {lead:true};}}
var best=null,bs=0;for(var i=0;i<KB.length;i++){var s=0;for(var k=0;k<KB[i].kw.length;k++){if(KB[i].kw[k]&&t.indexOf(KB[i].kw[k])>-1){s+=KB[i].kw[k].length;}}if(s>bs){bs=s;best=KB[i];}}
var wb=false;for(var b2=0;b2<BOOK.length;b2++){if(BOOK[b2]&&t.indexOf(' '+BOOK[b2])>-1){wb=true;break;}}
if(wb&&(!best||bs<6)){return {html:BOOKING.intro+'<br><span style="font-size:13px;color:#7c8a97">'+MSGS.tapOption+'</span>',cta:null,chips:BOOKING.options};}
var INFOQ=/^\s*(what|why|explain|tell me about)\b/i.test(text)&&!/\b(you|your|price|prices|cost|much|book|booking|hour|hours|open|membership|memberships)\b/i.test(text);
if(INFOQ){var kni=kSearch(text);if(kni){return knReply(kni);}}
if(best&&bs>=6){return {html:best.a,cta:best.cta,chips:best.chips};}
if(best&&bs>=4){return {html:best.a,cta:best.cta,chips:best.chips};}
var kn=kSearch(text);if(kn){return knReply(kn);}
return {html:MSGS.fallback,cta:null,chips:(KB[0]&&KB[0].chips)};}
function handleUser(text,label){if(!text||!text.trim())return;addMsg((label||text),'user');chips.innerHTML='';typing(function(){var r=answerFor(text);if(r.lead){startLead();return;}var html=r.html;if(r.cta){var L=(typeof r.cta[0]==='string')?[r.cta]:r.cta;var bh='';for(var ci=0;ci<L.length;ci++){bh+=cta(L[ci][0],L[ci][1]);}html+='<div class="cta-row">'+bh+'</div>';}addMsg(html,'bot');renderChips(r.chips?r.chips:STARTERS);});}
function openMindbody(url,title){closeMindbody();var ov=document.createElement('div');ov.className='mbo-overlay';ov.id='mbo-overlay';ov.innerHTML='<div class="mbo-box"><div class="mbo-head"><span>'+(title||MSGS.mboTitle)+'</span><a class="mbo-open" href="'+url+'" target="_blank" rel="noopener">Open in browser</a><button class="mbo-close" aria-label="Close">&times;</button></div><iframe src="'+url+'" allow="payment" title="Booking"></iframe></div>';document.body.appendChild(ov);ov.addEventListener('click',function(e){if(e.target===ov)closeMindbody();});ov.querySelector('.mbo-close').onclick=closeMindbody;}
function closeMindbody(){var o=document.getElementById('mbo-overlay');if(o&&o.parentNode)o.parentNode.removeChild(o);}
function openCalendly(url){if(window.Calendly&&window.Calendly.initPopupWidget){window.Calendly.initPopupWidget({url:url});return;}var s=document.getElementById('hos-cal-js'),done=false;var go=function(){if(done)return;done=true;if(window.Calendly&&window.Calendly.initPopupWidget){window.Calendly.initPopupWidget({url:url});}else{window.location.href=url;}};if(s){s.addEventListener('load',go);s.addEventListener('error',function(){if(!done){done=true;window.location.href=url;}});setTimeout(go,2500);}else{window.location.href=url;}}
window.addEventListener('message',function(e){if(!e||!e.data||typeof e.data!=='object'||e.data.event!=='calendly.event_scheduled')return;try{if(window.Calendly&&window.Calendly.closePopupWidget){window.Calendly.closePopupWidget();}}catch(err){}try{addMsg(MSGS.booked,'bot');renderChips(STARTERS);sd();}catch(err){}});
function showBooking(){chips.innerHTML='';typing(function(){addMsg(BOOKING.intro,'bot');renderChips(BOOKING.options);});}
function showBrowse(){chips.innerHTML='';typing(function(){var r=browseAnswer('__browse__');addMsg(r.html,'bot');renderChips(r.chips);});}
function startLead(){var html=(LEAD&&LEAD.intro)||'Leave your number and we will call you back.';if(LEAD&&LEAD.formUrl){html+='<div class="cta-row">'+cta((LEAD.buttonLabel||'Open the callback form'),LEAD.formUrl)+'</div>';}addMsg(html,'bot');renderChips(STARTERS);}
