document.body.addEventListener('click',function(e){if(!e.target||!e.target.closest)return;var calEl=e.target.closest('[data-hos-cal]');if(calEl){e.preventDefault();openCalendly(calEl.getAttribute('data-hos-cal'));return;}var mboEl=e.target.closest('[data-hos-mbo]');if(mboEl){e.preventDefault();openMindbody(mboEl.getAttribute('data-hos-mbo'),mboEl.getAttribute('data-mbo-title'));return;}if(e.target.closest('[data-hos-lead]')){e.preventDefault();startLead();return;}var keyEl=e.target.closest('[data-hos-key]');if(keyEl){e.preventDefault();handleUser('__key__:'+keyEl.getAttribute('data-hos-key'),keyEl.textContent.replace(/\s+/g,' ').trim());return;}var askEl=e.target.closest('[data-hos-ask]');if(askEl){e.preventDefault();handleUser(askEl.getAttribute('data-hos-ask'),askEl.textContent.replace(/\s+/g,' ').trim());return;}if(e.target.closest('[data-hos-browse]')){e.preventDefault();showBrowse();return;}if(e.target.closest('[data-hos-book]')){e.preventDefault();showBooking();}});
